/**
 * 基于 canvas.measureText api 计算并返回获取文字（指定字体）的 px 宽度
 * Uses canvas.measureText to compute and return the width of the given text of given font in pixels.
 * @param {String} text The text to be rendered.
 * @param {String} font The css font descriptor that text is to be rendered with (e.g. "bold 14px verdana").
 */
export const getTextWidth = <{ (t: string, font?: string): number; canvas?: HTMLCanvasElement }>(
    function (
        t: string,
        font = '13px -apple-system, BlinkMacSystemFont, PingFang SC, Hiragino Sans GB, Microsoft YaHei, Segoe UI, Helvetica Neue, Helvetica, Arial, sans-serif, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol',
    ) {
        // re-use canvas object for better performance
        const canvas =
            getTextWidth.canvas || (getTextWidth.canvas = document.createElement('canvas'));
        const context = canvas.getContext('2d') as CanvasRenderingContext2D;
        context.font = font;
        const metrics = context.measureText(t);
        return metrics.width;
    }
);